class Admin_Model_ProductMeta extends Admin_Model_Base_ProductMeta
{
    const DENIED_SHIPPING_METHOD = 'DENY_SHIPPING_METHOD';
    const REQUIRED_SHIPPING_METHOD = 'REQ_SHIPPING_METHOD';

    /**
     * @throws Doctrine_Query_Exception
     */
    public static function deleteProductMeta(int $productID) {
        $query = Doctrine_Query::create();
        $query->delete('Admin_Model_ProductMeta pm');
        $query->where('pm.Product_ID = ?', $productID);
        $query->execute();
    }

    /**
     * @throws Doctrine_Query_Exception
     */
    public static function getProductMetas(int $productID): Doctrine_Collection {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_ProductMeta pm');
        $query->where('pm.Product_ID = ?', $productID);
        return $query->execute();
    }

    public static function getDeniedShippingMethodCodes(array $productIds): array {
        $query = Doctrine_Query::create();
        $query->select('GROUP_CONCAT(DISTINCT pm.Value SEPARATOR ";") as DeniedShippingMethods');
        $query->from('Admin_Model_ProductMeta pm');
        $query->whereIn('pm.Product_ID', $productIds);
        $query->andWhere('pm.Code = ?', self::DENIED_SHIPPING_METHOD);
        $query->andWhere('pm.Value IS NOT NULL');
        $query->groupBy('pm.Product_ID');
        $result = $query->fetchOne();
        if ($result) {
            return explode(';', $result->DeniedShippingMethods);
        }
        return [];
    }

    public static function getRequiredShippingMethodCodes(array $productIds) {
        $query = Doctrine_Query::create();
        $query->select('pm.Value as RequiredShippingMethods');
        $query->from('Admin_Model_ProductMeta pm');
        $query->whereIn('pm.Product_ID', $productIds);
        $query->andWhere('pm.Code = ?', self::REQUIRED_SHIPPING_METHOD);
        $query->andWhere('pm.Value IS NOT NULL');
        $query->andWhere('pm.Value != ""');
        $query->groupBy('pm.Product_ID');
        $result = $query->execute([], Doctrine_Core::HYDRATE_ARRAY);

        $requiredShippingMethods = [];
        $hasPaletaMethod = false;

        foreach ($result as $item) {
            $requiredShippingValues = explode(';', $item['RequiredShippingMethods']);
            foreach ($requiredShippingValues as $shippingValue) {
                if (!isset($requiredShippingMethods[$shippingValue])) {
                    $requiredShippingMethods[$shippingValue] = 1;
                } else {
                    $requiredShippingMethods[$shippingValue] += 1;
                }
                if ($shippingValue === 'PALETA') {
                    $hasPaletaMethod = true;
                }
            }
        }

        //Cílem je získat společného dopravce pro všechny produkty, které mají REQ_SHIPPING_METHOD meta nastavenou
        $resultCount = count($result);
        $result = array_filter($requiredShippingMethods, function($item) use ($resultCount) {
            return $item == $resultCount;
        });

        $result = array_keys($result);

        if ($result) {
            return $result;
        }

        // Pokud neexistuje společný dopravce a někde je "PALETA", vrátíme pouze ji
        if (empty($result) && $hasPaletaMethod) {
            return ['PALETA'];
        }

        return [];
    }
}